using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Dr.", result);
        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.Contains("Johnson", result);
        Assert.EndsWith("Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.BuildGreeting(null!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("My Post! #1");

        Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("!!! Hello");

        Assert.StartsWith("hello", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello !!!");

        Assert.EndsWith("hello", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  Leading Spaces  ", "leading-spaces")]
    [DataRow("ALL CAPS TITLE", "all-caps-title")]
    [DataRow("multiple---dashes", "multiple-dashes")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string input, string expected)
    {
        var result = _formatter.GenerateSlug(input);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug("   "));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(49.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_WithCents_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(19.95m);

        Assert.AreEqual("$19.95", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(-5.5, "-$5.50")]
    [DataRow(1234.567, "$1234.57")]
    public void FormatCurrency_VariousAmounts_ReturnsExpectedFormat(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

